SELECT DISTINCT fuel_type
FROM fuelbeds
WHERE fuelbed_id IN (SELECT fuelbed_id FROM fire_incidents);

SELECT predicted_fire_behavior
FROM fire_behavior
WHERE fire_intensity = 'very high';

SELECT area
FROM fuelbeds
WHERE can_con_pct > 15 AND fuel_type = 'timber';

SELECT predicted_fire_behavior
FROM fire_behavior
ORDER BY fire_intensity DESC;

SELECT species
FROM vegetation
WHERE vegetation_id = 1;

SELECT COUNT(ecoregion_name) 
FROM ecoregions 
WHERE climate_zone = 'boreal';

SELECT fuelbed_id, SUM(area) AS total_area, MAX(fm_duff) AS max_duff_moisture
FROM fuelbeds
GROUP BY fuelbed_id;
